import{_ as t}from"./plugin-vue_export-helper-x3n3nnut.js";import{r as p,o,c as i,a as n,b as a,d as e,e as c}from"./app-VLgNDF8W.js";const l={},d=c(`<h1 id="混合开发" tabindex="-1"><a class="header-anchor" href="#混合开发" aria-hidden="true">#</a> 混合开发</h1><p>Hybrid App：混合了 Native（原生）技术和 web 技术进行开发的移动应用。主要有以三种方式：</p><ul><li><strong>基于<code>WebView UI(JSBridge)</code></strong>: 通过<code>JSBridge</code>完成<code>Web端</code>和<code>Native端</code>的通讯，从而赋予<code>Web端</code>原生能力</li><li><strong>基于<code>Native UI(ReactNative、Weex)</code></strong>: 在赋予<code>Web端</code>原生能力的基础之上，通过<code>JSBridge</code>将 js 解析成虚拟节点树(Virtual Dom)传递到<code>Native端</code>并使用原生渲染</li><li><strong>小程序方案(微信、支付宝小程序等)</strong>: 通过更加<code>定制化的JSBridge</code>，并使用<code>双 WebView</code>、<code>双线程</code>的模式隔离了<code>JS逻辑</code>与<code>UI渲染</code>，形成了特殊的开发模式，加强了 Web 端与 Native 端混合程度，提高了页面性能及开发体验。</li></ul><h2 id="hybrid-app-的本质" tabindex="-1"><a class="header-anchor" href="#hybrid-app-的本质" aria-hidden="true">#</a> Hybrid App 的本质</h2><p>在原生(Native) APP 中，使用<code>WebView</code>作为容器，来承载一个 Web 页面。</p><p>原生(Native)和 Web 端的双向通讯层(跨语言解决方案) —— <code>JSBridge</code></p><ul><li>定义: 用 JavaScript 搭建起来的桥, 一端是 Web 端, 一端是 Native。</li><li>目的: 让 Native 端可以调用 Web 的 JavaScript 代码, 让 Web 端可以调用 Native 的原生代码</li></ul><h2 id="web端通知native端" tabindex="-1"><a class="header-anchor" href="#web端通知native端" aria-hidden="true">#</a> <code>Web端</code>通知<code>Native端</code></h2><p>Web 端通知 Native 端三种常见方案:</p><h3 id="_1-api-注入" tabindex="-1"><a class="header-anchor" href="#_1-api-注入" aria-hidden="true">#</a> 1. API 注入</h3><p>通过<code>向Window注入对象</code>的方式来提供可被 Web 端调用的方法。Android 端可直接<code>获取注入对象，调用方法</code>；IOS 端则为相对固定写法(<code>window.webkit.messageHandlers.方法名.postMessage(入参对象)</code>)</p><ul><li><p>相同点</p><ul><li>通过<code>WebView</code>来完成网页的加载</li><li>通过<code>向Window注入对象</code>的方式来提供可被 Web 端调用的方法</li><li>可以直接调用 Web 端<code>挂载到Window对象</code>下的方法</li></ul></li><li><p>不同点</p><table><thead><tr><th></th><th style="text-align:left;">Android</th><th style="text-align:left;">IOS</th></tr></thead><tbody><tr><td>注入对象</td><td style="text-align:left;">可提供<code>注入对象名</code></td><td style="text-align:left;">固定为<code>webkit</code></td></tr><tr><td>JS 调用 Native 方式</td><td style="text-align:left;">可直接<code>获取注入对象，调用方法</code></td><td style="text-align:left;">相对固定写法(<code>window.webkit.messageHandlers.方法名.postMessage(入参对象)</code>)</td></tr><tr><td>传递数据格式</td><td style="text-align:left;">只能接受<code>基本类型数据</code></td><td style="text-align:left;">可以接受<code>任意类型数据</code></td></tr><tr><td>返回值</td><td style="text-align:left;">可直接接受返回值</td><td style="text-align:left;">无法直接获取返回值</td></tr></tbody></table></li></ul><h3 id="_2-webview-中prompt-console-alert拦截" tabindex="-1"><a class="header-anchor" href="#_2-webview-中prompt-console-alert拦截" aria-hidden="true">#</a> 2. WebView 中<code>prompt/console/alert</code>拦截</h3><p>通常拦截<code>prompt</code>，因为在前端中使用频率低。(prompt()方法用于显示可提示用户进行输入的对话框)</p><h3 id="_3-webview-url-scheme-跳转拦截方式" tabindex="-1"><a class="header-anchor" href="#_3-webview-url-scheme-跳转拦截方式" aria-hidden="true">#</a> 3. WebView URL Scheme 跳转拦截方式</h3><p>第二种、第三种原理类似，通过对 WebView 信息冒泡传递的拦截，从而达到通讯。</p><p>解析: <code>原理 --&gt; 定制协议 --&gt; 拦截协议 --&gt; 参数传递 --&gt; 回调机制</code></p><ul><li><p>原理: 在 WebView 中发出的网络请求，客户端都能进行监听和捕获</p></li><li><p>定制协议</p><p>制定一套 URL Scheme 规则，可将协议类型的请求订制为: <code>xxcommand://xxxx?param1=1&amp;param2=2</code>。(通常请求会带有对应的协议开头，例如<code>https://xxx.com</code> 或者<code>file://1.jpg</code>。)</p><ul><li><code>xxcommand://</code> 只是一种规则，可以根据业务进行制定，使其具有含义。<strong>不同的协议头代表着不同的含义，这样便能清楚知道每个协议的适用范围。</strong>(<code>xxcommand://</code>为通用工具协议，<code>xxapp://</code> 为每个 App 单独的业务协议。)</li><li>不要使用<code>location.href</code>发送，因为其自身机制存在问题，同时并发多次请求会被合并成为一次，导致协议被忽略，而并发协议其实是非常常见的功能。我们会使用<code>创建 iframe 发送请求</code>的方式。</li><li>在客户端中设置域名白名单或者限制，避免公司内部业务协议被第三方直接调用。</li></ul></li><li><p>拦截协议: 客户端可以通过 API 对 WebView 发出的请求进行拦截</p><ul><li>Android: <code>shouldOverrideUrlLoading</code></li><li>IOS: <code>shouldStartLoadWithRequest</code></li></ul><p>当解析到请求 URL 头为制定的协议时，便不发起对应的资源请求，而是<strong>解析参数，并进行相关功能或者方法的调用</strong>，完成协议功能的映射。</p></li><li><p>协议回调</p><p>由于协议的本质其实是发送请求，这属于异步的过程，因此需要处理对应的回调机制。采用的方式是 <strong><code>JS的事件系统</code></strong>，会用到两个基础 API <code>window.addEventListener</code> 和 <code>window.dispatchEvent</code></p><ul><li><p>发送协议时，通过协议的唯一标识注册自定义事件，并将回调绑定到对应的事件上。</p></li><li><p>客户端完成对应的功能后，调用<code>Bridge</code>的<code>dispatch API</code>，直接携带 data 触发该协议的自定义事件。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>Bridge<span class="token punctuation">.</span><span class="token function">getNetwork</span><span class="token punctuation">(</span><span class="token parameter">data</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span> <span class="token comment">// 业务调用API</span>
<span class="token comment">// Bridge层功能：生成唯一标识 handler；注册自定义事件；拼接参数并发送协议</span>
<span class="token keyword">const</span> handler <span class="token operator">=</span> <span class="token number">1</span>
window<span class="token punctuation">.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">getNetwork_</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>handler<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">,</span> callback<span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span>
Bridge<span class="token punctuation">.</span><span class="token function">send</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">xxcommand://getNetwork?handler=</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>handler<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span>
<span class="token comment">// Native层获取网络状态后通过bridge再次传回，将网络状态通过事件直接出发自定义事件并传递参数</span>
event<span class="token punctuation">.</span>data <span class="token operator">=</span> network
window<span class="token punctuation">.</span><span class="token function">dispatchEvent</span><span class="token punctuation">(</span>event<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>应该避免事件的多次重复绑定，因此当唯一标识重置时，需要<code>removeEventListener</code>对应的事件。</p></li></ul></li><li><p>参数传递方式</p><p>由于 WebView 对 URL 会有长度的限制，当需要传递的参数过长时，可能会导致被截断。所以使用<code>函数调用</code>的方式。这里的原理主要是基于: <strong><code>Native 可以直接调用 JS 方法并直接获取函数的返回值</code></strong>。只需要对每条协议标记一个唯一标识，并把参数存入参数池中，客户端再通过该唯一标识从参数池中获取对应的参数即可。</p></li></ul><h2 id="native端通知web端" tabindex="-1"><a class="header-anchor" href="#native端通知web端" aria-hidden="true">#</a> <code>Native端</code>通知<code>Web端</code></h2><p>Native 可以通过<code>WebView API</code>直接执行 JS 代码</p><ul><li><p>Android</p><ul><li><p><code>loadUrl</code> (版本 4.4-)</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token comment">// 调用js中的JSBridge.trigger方法, 该方法的弊端是无法获取函数返回值</span>
webView<span class="token punctuation">.</span><span class="token function">loadUrl</span><span class="token punctuation">(</span><span class="token string">&quot;javascript:JSBridge.trigger(&#39;NativeCall&#39;)&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>当系统低于 4.4 时，evaluateJavascript 是无法使用的，因此单纯的使用 loadUrl 无法获取 JS 返回值，需要使用<code>prompt</code>的方法进行兼容，让 H5 端通过<code>prompt</code>进行数据的发送，客户端进行拦截并获取数据。</p></li><li><p><code>evaluateJavascript</code> (版本 4.4+)</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token comment">// 4.4+后使用该方法便可调用并获取函数返回值；</span>
mWebView<span class="token punctuation">.</span><span class="token function">evaluateJavascript</span><span class="token punctuation">(</span><span class="token string">&quot;javascript:JSBridge.trigger(&#39;NativeCall&#39;)&quot;</span><span class="token punctuation">,</span> <span class="token keyword">new</span> <span class="token class-name">ValueCallback</span><span class="token generics"><span class="token punctuation">&lt;</span><span class="token class-name">String</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token annotation punctuation">@Override</span>
  <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">onReceiveValue</span><span class="token punctuation">(</span><span class="token class-name">String</span> value<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">//此处为 js 返回的结果</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul></li><li><p>IOS: <code>stringByEvaluatingJavaScriptFromString</code></p><div class="language-swift line-numbers-mode" data-ext="swift"><pre class="language-swift"><code>webview<span class="token punctuation">.</span><span class="token function">stringByEvaluatingJavaScriptFromString</span><span class="token punctuation">(</span><span class="token string-literal"><span class="token string">&quot;alert(&#39;NativeCall&#39;)&quot;</span></span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></li></ul><h2 id="jsbridge-的接入" tabindex="-1"><a class="header-anchor" href="#jsbridge-的接入" aria-hidden="true">#</a> JSBridge 的接入</h2><ul><li><strong>JS 部分(bridge)</strong>: 在 JS 环境中注入 bridge 的实现代码，包含了协议的拼装/发送/参数池/回调池等一些基础功能。</li><li><strong>Native 部分(SDK)</strong>: 在客户端中 bridge 的功能映射代码，实现了 URL 拦截与解析/环境信息的注入/通用功能映射等功能。</li></ul><p>将这两部分封装成一个 <code>Native SDK</code>，由客户端统一引入。客户端在初始化一个 WebView 打开页面时，如果页面地址在白名单中，会直接在 HTML 的头部注入对应的 bridge.js。这样的做法有以下的好处:</p><ul><li>双方的代码统一维护，避免出现版本分裂的情况。有更新时，只要由客户端更新 SDK 即可，不会出现版本兼容的问题；</li><li>App 的接入十分方便，只需要按文档接入最新版本的 SDK，即可直接运行整套 Hybrid 方案，便于在多个 App 中快速的落地；</li><li>H5 端无需关注，这样有利于将 bridge 开放给第三方页面使用。</li></ul><p><strong>协议的调用，一定是需要确保执行在 bridge.js 成功注入后</strong>。由于客户端的注入行为属于一个附加的异步行为，从 H5 方很难去捕捉准确的完成时机，因此需要通过客户端监听页面完成后，基于上面的事件回调机制通知 H5 端，页面中即可通过<code>window.addEventListener(&#39;bridgeReady&#39;, e =&gt; {})</code>进行初始化。</p><h2 id="app-中-h5-的接入方式" tabindex="-1"><a class="header-anchor" href="#app-中-h5-的接入方式" aria-hidden="true">#</a> APP 中 H5 的接入方式</h2><ul><li><p>在线 H5: 将 H5 代码部署到服务器上，只要把对应的 URL 地址 给到客户端，用 WebView 打开该 URL，即可嵌入。</p><ul><li>优点: <ul><li>独立性强，有非常独立的开发/调试/更新/上线能力</li><li>资源放在服务器上，完全不会影响客户端的包体积</li><li>接入成本很低，完全的热更新机制</li></ul></li><li>缺点: <ul><li>完全的网络依赖，在离线的情况下无法打开页面</li><li>首屏加载速度依赖于网络，网络较慢时，首屏加载也较慢</li></ul></li></ul><p>通常，这种方式更适用在一些比较轻量级的页面上，例如一些帮助页、提示页、使用攻略等页面。这些页面的特点是<strong>功能性不强，不太需要复杂的功能协议，且不需要离线使用</strong>。在一些第三方页面接入上，也会使用这种方式，例如页面调用微信 JS-SDK。</p></li><li><p>内置包 H5: 本地化的嵌入方式，将代码进行打包后下发到客户端，并由客户端直接解压到本地储存中。通常运用在一些比较大和比较重要的模块上。</p><ul><li>优点: <ul><li>由于其本地化，首屏加载速度快，用户体验更为接近原生</li><li>可以不依赖网络，离线运行</li></ul></li><li>缺点: <ul><li>开发流程/更新机制复杂化，需要客户端，甚至服务端的共同协作</li><li>会相应的增加 App 包体积</li></ul></li></ul></li></ul><h2 id="webview-url-scheme-跳转拦截实现" tabindex="-1"><a class="header-anchor" href="#webview-url-scheme-跳转拦截实现" aria-hidden="true">#</a> WebView URL Scheme 跳转拦截实现</h2><h3 id="bridge-js-架构" tabindex="-1"><a class="header-anchor" href="#bridge-js-架构" aria-hidden="true">#</a> bridge.js 架构</h3><p>核心代码：</p><ul><li>最重要的开放 API: <code>nativeCall</code> 与 <code>postMessage</code></li><li>客户端获取参数函数: <code>getParam</code></li><li>事件回调系统中的 <code>addEvent</code> 和 <code>fireEvent</code></li><li>用于发送协议的 <code>send</code></li></ul><h4 id="使用示例-获取网络状态为例" tabindex="-1"><a class="header-anchor" href="#使用示例-获取网络状态为例" aria-hidden="true">#</a> 使用示例(获取网络状态为例)</h4><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>Bridge<span class="token punctuation">.</span><span class="token function">nativeCall</span><span class="token punctuation">(</span><span class="token string">&#39;getNetwork&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token parameter">e</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>e<span class="token punctuation">.</span>data <span class="token operator">&amp;&amp;</span> e<span class="token punctuation">.</span>data<span class="token punctuation">.</span>type <span class="token operator">===</span> <span class="token number">0</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// 无网络状态</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    <span class="token comment">// type: wifi/2g/3g/4g</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="h5-native" tabindex="-1"><a class="header-anchor" href="#h5-native" aria-hidden="true">#</a> H5 --&gt; Native</h4><ul><li><p>H5</p><ul><li>生成唯一 <code>handler</code> 标识，从 0 开始累加</li><li>将参数按 <code>handler</code> 值的规则存入参数池(<code>_paramsStore</code>)中</li><li>以 <code>handler</code> 注册自定义事件，绑定 <code>callback</code>，并将 callback 也存入 <code>_callbackStore</code> 中，注册自定义事件 <code>addEvent()</code>。储存的目的主要是为了事件解绑时使用</li><li>以<code>iframe的形式</code>发送协议，并携带唯一标识 handler，发送协议请求 send()</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">let</span> i <span class="token operator">=</span> <span class="token number">0</span>
<span class="token keyword">function</span> <span class="token function">nativeCall</span><span class="token punctuation">(</span><span class="token parameter">scheme <span class="token operator">=</span> <span class="token function">throwError</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> params<span class="token punctuation">,</span> callback</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// 对参数进行字符串化，并进行编码</span>
  params <span class="token operator">=</span> params <span class="token operator">?</span> <span class="token function">decode</span><span class="token punctuation">(</span><span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span>params<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">:</span> <span class="token string">&#39;&#39;</span>
  <span class="token comment">// 生成唯一 handler 标识</span>
  <span class="token keyword">const</span> handler <span class="token operator">=</span> i<span class="token operator">++</span><span class="token punctuation">,</span>
    handlerKey <span class="token operator">=</span> <span class="token function">getHandlerKey</span><span class="token punctuation">(</span>handler<span class="token punctuation">)</span>
  <span class="token comment">// 将参数存储进参数池</span>
  _paramsStore<span class="token punctuation">.</span><span class="token function">save</span><span class="token punctuation">(</span>handlerKey<span class="token punctuation">.</span>p<span class="token punctuation">,</span> params<span class="token punctuation">)</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">isFn</span><span class="token punctuation">(</span>callback<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// 将回调储存进回调池</span>
    _callbackStore<span class="token punctuation">.</span><span class="token function">save</span><span class="token punctuation">(</span>handlerKey<span class="token punctuation">.</span>c<span class="token punctuation">,</span> callback<span class="token punctuation">)</span>
    <span class="token comment">// 注册自定义事件，并绑定回调：回调会在接受到 postMessage 时被触发执行</span>
    <span class="token function">addEvent</span><span class="token punctuation">(</span>handlerKey<span class="token punctuation">.</span>e<span class="token punctuation">,</span> <span class="token parameter">e</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
      <span class="token keyword">const</span> <span class="token punctuation">{</span> data<span class="token punctuation">,</span> handler <span class="token punctuation">}</span> <span class="token operator">=</span> e<span class="token punctuation">.</span>data
      <span class="token comment">// 完成一次完整交互时，将自定义事件解绑</span>
      <span class="token function">removeEvent</span><span class="token punctuation">(</span>handler<span class="token punctuation">)</span>
      <span class="token function">callback</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>MTJs<span class="token punctuation">,</span> data<span class="token punctuation">)</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
  <span class="token comment">// 发送协议请求</span>
  <span class="token function">send</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>scheme<span class="token interpolation-punctuation punctuation">}</span></span><span class="token string">?handler=</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>handler<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>

<span class="token keyword">function</span> <span class="token function">send</span><span class="token punctuation">(</span><span class="token parameter">scheme</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token function">setTimeout</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
    <span class="token comment">// 创建 iframe 并设置 src</span>
    <span class="token keyword">const</span> iframe <span class="token operator">=</span> document<span class="token punctuation">.</span><span class="token function">createElement</span><span class="token punctuation">(</span><span class="token string">&#39;iframe&#39;</span><span class="token punctuation">)</span>
    iframe<span class="token punctuation">.</span>src <span class="token operator">=</span> scheme
    iframe<span class="token punctuation">.</span>style<span class="token punctuation">.</span>display <span class="token operator">=</span> <span class="token string">&#39;none&#39;</span>
    document<span class="token punctuation">.</span>body<span class="token punctuation">.</span><span class="token function">appendChild</span><span class="token punctuation">(</span>iframe<span class="token punctuation">)</span>
    <span class="token comment">// 延迟删除节点</span>
    <span class="token function">setTimeout</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
      iframe<span class="token punctuation">.</span>parentNode<span class="token punctuation">.</span><span class="token function">removeChild</span><span class="token punctuation">(</span>iframe<span class="token punctuation">)</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token number">300</span><span class="token punctuation">)</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span>
  <span class="token keyword">return</span> <span class="token keyword">this</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>Native</p><ul><li><p>客户端接收到请求后，会使用 <code>handler</code> 调用 <code>getParam</code> 从参数池中获取对应的参数。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">getParam</span><span class="token punctuation">(</span><span class="token parameter">handler <span class="token operator">=</span> <span class="token function">throwError</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> key <span class="token operator">=</span> <span class="token function">getHandlerKey</span><span class="token punctuation">(</span>handler<span class="token punctuation">)</span><span class="token punctuation">.</span>p
  <span class="token keyword">return</span> _paramsStore<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span>key<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>执行协议对应的功能</p></li></ul></li></ul><h4 id="native-h5" tabindex="-1"><a class="header-anchor" href="#native-h5" aria-hidden="true">#</a> Native --&gt; H5</h4><ul><li>Native: Native 完成功能后，直接调用 <code>Bridge.postMessage(handler, data)</code>，将执行结果和之前<code>nativeCall</code>传过来的<code>标识</code>回传给<code>H5</code>。</li><li>H5: H5 在接收到唯一标识后初始化对应的自定义事件，挂载数据后触发。</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">postMessage</span><span class="token punctuation">(</span><span class="token parameter">e</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// 客户端携带 handler 和 data 调用 postMessage</span>
  <span class="token keyword">const</span> <span class="token punctuation">{</span> handler<span class="token punctuation">,</span> data <span class="token punctuation">}</span> <span class="token operator">=</span> e
  <span class="token comment">// 获取对象的自定义事件名 e__handler</span>
  <span class="token keyword">const</span> evName <span class="token operator">=</span> <span class="token function">getHandlerKey</span><span class="token punctuation">(</span>handler<span class="token punctuation">)</span><span class="token punctuation">.</span>e
  <span class="token comment">// 创建并触发自定义事件</span>
  <span class="token function">fireEvent</span><span class="token punctuation">(</span>evName<span class="token punctuation">,</span> e<span class="token punctuation">)</span>
  <span class="token keyword">return</span> <span class="token keyword">this</span>
<span class="token punctuation">}</span>

<span class="token keyword">function</span> <span class="token function">fireEvent</span><span class="token punctuation">(</span><span class="token parameter">evName<span class="token punctuation">,</span> data</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// 创建自定义事件对象</span>
  <span class="token keyword">let</span> eventItem
  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">isFn</span><span class="token punctuation">(</span>doc<span class="token punctuation">.</span>CustomEvent<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    eventItem <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">doc<span class="token punctuation">.</span>CustomEvent</span><span class="token punctuation">(</span>evName<span class="token punctuation">,</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">bubbles</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span>
      <span class="token literal-property property">cancelable</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">isFn</span><span class="token punctuation">(</span>doc<span class="token punctuation">.</span>createEvent<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    eventItem <span class="token operator">=</span> doc<span class="token punctuation">.</span><span class="token function">createEvent</span><span class="token punctuation">(</span><span class="token string">&#39;Event&#39;</span><span class="token punctuation">)</span>
    eventItem<span class="token punctuation">.</span><span class="token function">initEvent</span><span class="token punctuation">(</span>evName<span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
  <span class="token comment">// 将数据挂载到事件对象中</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>data <span class="token operator">&amp;&amp;</span> eventItem<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    eventItem<span class="token punctuation">.</span>data <span class="token operator">=</span> data
  <span class="token punctuation">}</span>
  <span class="token comment">// 触发自定义事件</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>eventItem<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    win<span class="token punctuation">.</span><span class="token function">dispatchEvent</span><span class="token punctuation">(</span>eventItem<span class="token punctuation">)</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    <span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;Bridge Error: dispatchEvent&#39;</span><span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
  <span class="token keyword">return</span> <span class="token keyword">this</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="android-兼容性" tabindex="-1"><a class="header-anchor" href="#android-兼容性" aria-hidden="true">#</a> Android 兼容性</h4><p>问题: 在 <code>Android 4.4</code> 以下时，使用的 <code>loadUrl</code> 进行 js 函数的调用，此时是无法获取函数的返回值的，即：<code>Android 4.4-</code> 时，安卓并无法通过 · 这个函数来获取到协议的参数，需要做兼容性的处理。</p><p>解决方法: WebView 中的 <code>prompt</code> 拦截</p><ul><li><p>当安卓接受到协议，并拿到 <code>handler</code> 值</p></li><li><p>使用无兼容性问题的 <code>loadUrl</code> 执行 <code>js：Bridge.getParam(handler)</code> ，直接将返回值直接通过 js 中的 prompt 发出：</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code>webview<span class="token punctuation">.</span><span class="token function">loadUrl</span><span class="token punctuation">(</span><span class="token string">&quot;javascript:prompt(&#39;Bridge:commonJsExecute#1&#39;, Bridge.getParam(1))&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></li><li><p>通过重写 <code>onJsPrompt</code> 这个方法，拦截上一步发出的 <code>prompt</code> 的内容，并解析出相应的参数</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token annotation punctuation">@Override</span>
<span class="token keyword">public</span> <span class="token keyword">boolean</span> <span class="token function">onJsPrompt</span><span class="token punctuation">(</span><span class="token class-name">WebView</span> webiew<span class="token punctuation">,</span> <span class="token class-name">String</span> url<span class="token punctuation">,</span> <span class="token class-name">String</span> message<span class="token punctuation">,</span> <span class="token class-name">String</span> defaultValue<span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// 获取 prompt 内容 message，匹配并解析出对应的参数字符串，并解析</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul><h3 id="协议的制定" tabindex="-1"><a class="header-anchor" href="#协议的制定" aria-hidden="true">#</a> 协议的制定</h3><p>可将协议分成<strong>功能协议</strong>和<strong>业务协议</strong></p><h4 id="功能协议" tabindex="-1"><a class="header-anchor" href="#功能协议" aria-hidden="true">#</a> 功能协议</h4><p>用于完善整套方案的基础功能的一些通用协议，以 command://作为通用头，封装在 SDK 之中，可以在全线 App、全线 WebView 中使用。</p><ul><li><p>初始化机制</p><p>由于 bridge.js 注入的异步性，需要由客户端在注入完成后通知 H5。通用的初始化事件，这里约定为 <em>init</em></p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 用于标记避免事件被重复触发</span>
<span class="token comment">// 由于客户端中是通过监听 WebView 的生命周期钩子来触发的，而 iframe 之类的操作会导致这些钩子的多次触发，因此需要双方各做一层防御性措施。</span>
<span class="token keyword">let</span> isLoaded <span class="token operator">=</span> <span class="token boolean">false</span>
window<span class="token punctuation">.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span>
  <span class="token string">&#39;_init_&#39;</span><span class="token punctuation">,</span>
  <span class="token parameter">e</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>isLoaded<span class="token punctuation">)</span> <span class="token keyword">return</span> <span class="token boolean">false</span>
    isLoaded <span class="token operator">=</span> <span class="token boolean">true</span>
    <span class="token comment">// 代码逻辑...</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token boolean">false</span>
<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>通过该事件，直接初始化传给 H5 一些环境参数和系统信息等</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>e<span class="token punctuation">.</span>data <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;CloudFilter&#39;</span><span class="token punctuation">,</span> <span class="token comment">// 应用名</span>
  <span class="token literal-property property">appVersion</span><span class="token operator">:</span> <span class="token string">&#39;1.0.0&#39;</span><span class="token punctuation">,</span> <span class="token comment">// app版本号</span>
  <span class="token literal-property property">version</span><span class="token operator">:</span> <span class="token string">&#39;1.112&#39;</span><span class="token punctuation">,</span> <span class="token comment">// H5包版本号</span>
  <span class="token literal-property property">platform</span><span class="token operator">:</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token comment">// 平台 - 1: ios; 2: Android</span>
  <span class="token literal-property property">area</span><span class="token operator">:</span> <span class="token string">&#39;中国大陆&#39;</span><span class="token punctuation">,</span> <span class="token comment">// 地区</span>
  <span class="token literal-property property">language</span><span class="token operator">:</span> <span class="token string">&#39;zh&#39;</span><span class="token punctuation">,</span> <span class="token comment">// 语言</span>
  <span class="token literal-property property">env</span><span class="token operator">:</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token comment">// 当前App环境 - 0: release; 1: pre; 2: dev</span>
  <span class="token literal-property property">data</span><span class="token operator">:</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token comment">// 参数池</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>可以约定更多的页面生命周期事件</strong>。例如因为 App 很经常性的隐藏到后台，因此在被激活时，我们可以设置个生命周期: <em>resume</em>，可以用于告知 H5 页面被激活。</p></li><li><p>包更新机制</p><p>问题: Hybrid 模块 的其中一种方式是将前端代码打包后内置于 App 本地，以便拥有最快的启动性能和离线访问能力。这种方式最大的麻烦点：代码的更新</p><p>解决方法: 需要一套<strong>新的热更新机制</strong>，这套机制需要由<strong>客户端/前端/服务端</strong>三端提供对应的资源，共同协作完成整套流程。</p><ul><li><p>资源</p><ul><li>H5: 每个代码包都有一个唯一且递增的版本号</li><li>Native: 提供包下载且解压到对应目录的服务，前端可以由下面这个协议来调用该功能。</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>Bridge<span class="token punctuation">.</span><span class="token function">nativeCall</span><span class="token punctuation">(</span><span class="token string">&#39;downloadModule&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">module</span><span class="token operator">:</span> appName<span class="token punctuation">,</span> <span class="token comment">// 应用名称</span>
  <span class="token literal-property property">url</span><span class="token operator">:</span> zipUrl<span class="token punctuation">,</span> <span class="token comment">// 最新包线上地址</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>服务端: 提供一个接口，可以获取线上最新代码包的版本号和下载地址。</li></ul></li><li><p>流程</p><ul><li>前端更新代码打包后按版本号上传至指定的服务器上</li><li>每次打开页面时，H5 请求接口<strong>获取线上最新代码包版本号</strong>，并与本地包进行<strong>版本号比对</strong>，当线上的版本号 大于 本地包版本号时，<strong>发起包下载协议</strong></li><li>客户端接收到协议后，直接去线上地址<strong>下载最新的代码包，并解压替换到当前目录文件</strong></li></ul></li></ul></li><li><p>环境系统 和 多语言系统</p><p>可以通过 <em>init</em> 中携带的数据 data.env 来匹配</p><p>环境机制通常主要用于匹配后端的环境，正式环境和测试环境对应不同的接口。还需要注意代码包的更新，包更新条件要包含三个方面: 版本号、环境和 App 版本，在不同环境不同 App 版本下，也应该更新到相应的最新代码包。</p></li><li><p>事件中转站</p><p>当页面中有弹窗或者 SPA 切换页面时，<strong>安卓的返回实体键</strong>应该能完成对应的回退，而不是因为 WebView 没有 history 就直接关闭。</p><p>可以定制一个事件中心(<em>eventListeners</em> )，用于监听客户端的实体返回键：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 事件中心</span>
<span class="token function">addEvent</span><span class="token punctuation">(</span><span class="token string">&#39;_eventListeners&#39;</span><span class="token punctuation">,</span> <span class="token parameter">e</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> type <span class="token operator">=</span> e<span class="token punctuation">.</span>data<span class="token punctuation">.</span>type
  <span class="token keyword">switch</span> <span class="token punctuation">(</span>type<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">case</span> <span class="token string">&#39;back&#39;</span><span class="token operator">:</span>
      <span class="token comment">// 关闭弹窗: this.closeDialog()</span>
      <span class="token comment">// 退回页面: this.goLastPage()</span>
      <span class="token keyword">break</span>
    <span class="token keyword">case</span> <span class="token string">&#39;hideLoading&#39;</span><span class="token operator">:</span>
      <span class="token comment">// 隐藏loading: this.hideLoading()</span>
      <span class="token keyword">break</span>
    <span class="token keyword">default</span><span class="token operator">:</span>
      <span class="token keyword">break</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>数据传递机制</p><p>很多场景需要做到 Native 与 H5 保持数据的同步，此时就可以使用类似上面的原理，制定一套数据传递协议:</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 推送数据</span>
Bridge<span class="token punctuation">.</span><span class="token function">nativeCall</span><span class="token punctuation">(</span><span class="token string">&#39;putData&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">a</span><span class="token operator">:</span> <span class="token number">1</span><span class="token punctuation">,</span>
  <span class="token literal-property property">b</span><span class="token operator">:</span> <span class="token number">2</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token comment">// 监听数据通道</span>
<span class="token function">addEvent</span><span class="token punctuation">(</span><span class="token string">&#39;getData&#39;</span><span class="token punctuation">,</span> <span class="token parameter">e</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token comment">// type: 代表数据类型，可自行约定</span>
  <span class="token comment">// data: 数据</span>
  <span class="token keyword">const</span> <span class="token punctuation">{</span> type<span class="token punctuation">,</span> data <span class="token punctuation">}</span> <span class="token operator">=</span> e<span class="token punctuation">.</span>data
  <span class="token keyword">switch</span> <span class="token punctuation">(</span>type<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">case</span> <span class="token string">&#39;list&#39;</span><span class="token operator">:</span>
      <span class="token comment">// 获取客户端传递过来的列表数据 data</span>
      <span class="token keyword">break</span>
    <span class="token keyword">default</span><span class="token operator">:</span>
      <span class="token keyword">break</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Hybrid 模块通常需要从对应的入口进入，因此有一种可以优化的方式：<strong>由 App 在启动时先去获取线上数据，在进入 WebView 后直接通过 <em>init</em> 或者触发 getData 直接发送给 H5</strong>，这样能减少请求数量，优化用户体验。</p></li><li><p>代理请求</p><p>H5 中最常用的就是请求，通常我们可以直接使用 ajax，但是这里有几个问题比较棘手:</p><ul><li>最常见的请求跨域</li><li>数据算法加密</li><li>用户登录校验</li></ul><p>客户端的请求便不会出现这些问题，因此我们可以由客户端代理我们发出的请求，可以定制 4 个协议: <code>getProxy</code>、<code>postProxy</code>、<code>getProxyLogined</code>、<code>postProxyLogined</code>，其中带有 <code>Logined</code> 的协议代表着在请求时会自动携带已登录用户的 <code>token</code> 和 <code>uid</code> 等参数，使用在一些需要登录信息的接口上。这样做的好处是:</p><ul><li>H5 方就无需处理繁多的各项复杂信息，不需要进行跨端传输</li><li>能够对 H5 与 Native 的请求出口进行统一，方便加工处理</li></ul><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>Bridge<span class="token punctuation">.</span><span class="token function">nativeCall</span><span class="token punctuation">(</span><span class="token string">&#39;getProxy&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">{</span> url<span class="token punctuation">,</span> data<span class="token punctuation">,</span> headers <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token parameter">e</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>e<span class="token punctuation">.</span>data <span class="token operator">&amp;&amp;</span> e<span class="token punctuation">.</span>data<span class="token punctuation">.</span>code <span class="token operator">==</span> <span class="token number">110</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// 请求失败</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    <span class="token comment">// 请求成功，返回数据 e.data</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>更多通用性协议</p><p>定义更多的通用性协议，这里有个原则可以遵守，即协议应该是<strong>基础性功能，应该是纯净的，适用于所有的业务方</strong>。</p><ul><li><code>getNetwork</code>：获取网络状态；</li><li><code>openApp</code>：唤起其它 App；</li><li><code>setShareInfo</code>与<code>callShare</code>：分享内容到第三方平台；</li><li><code>link</code>：使用新的 WebView 打开页面；</li><li><code>closeWebview</code>：关闭 WebView；</li><li><code>setStorage</code> 与 <code>getStorage</code>：设置与获取缓存数据；</li><li><code>loading</code>：调用客户端通用 Loading；</li><li><code>setWebviewTitle</code>：设置 WebView 标题；</li><li><code>saveImage</code>：保存图片到本地；</li><li>...</li></ul></li></ul><h4 id="业务协议" tabindex="-1"><a class="header-anchor" href="#业务协议" aria-hidden="true">#</a> 业务协议</h4><p>这类协议区别于功能协议，它们会杂合一定程度的业务逻辑，而这些逻辑只是针对于特定的项目。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 示例</span>
Bridge<span class="token punctuation">.</span><span class="token function">nativeCall</span><span class="token punctuation">(</span>
  <span class="token string">&#39;app://getResultImage&#39;</span><span class="token punctuation">,</span>
  <span class="token punctuation">{</span>
    category_id<span class="token punctuation">,</span>
    <span class="token literal-property property">material_id</span><span class="token operator">:</span> materialId<span class="token punctuation">,</span>
    <span class="token literal-property property">subcat_id</span><span class="token operator">:</span> subcatId<span class="token punctuation">,</span>
    origin_image<span class="token punctuation">,</span>
    zip_url<span class="token punctuation">,</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token parameter">data</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
    <span class="token comment">// 获取处理后的效果图路径</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>参考:</p>`,52),u={href:"https://github.com/xd-tayde/blog/blob/master/hybrid-1.md",target:"_blank",rel:"noopener noreferrer"},r={href:"https://github.com/xd-tayde/blog/blob/master/hybrid-2.md",target:"_blank",rel:"noopener noreferrer"};function k(v,m){const s=p("ExternalLinkIcon");return o(),i("div",null,[d,n("ul",null,[n("li",null,[n("a",u,[a("Hybrid App 技术解析 -- 原理篇"),e(s)])]),n("li",null,[n("a",r,[a("Hybrid App 技术解析 -- 实战篇"),e(s)])])])])}const h=t(l,[["render",k],["__file","混合开发.html.vue"]]);export{h as default};
